mapper.select:
/* com.shop.mapper.frontWeb.contents.selectContentsInfoListPaging */ SELECT CN.ID AS id , CN.NEWS_TYPE AS newsType , CN.NEWS_TITLE AS newsTitle , CN.NEWS_SUB_TITLE AS newsSubTitle , CN.NEWS_CONTENTS AS newsContents , CN.FILE_ID AS fileId , CN.PARTNER_ID AS partnerId , FD.SYS_FILE_NM AS sysFileNm FROM TB_CONTENTS CN LEFT JOIN TB_FILE_DET FD ON FD.FILE_ID = CN.FILE_ID AND FD.DEL_YN = 'N' AND FD.FILE_SEQ = 1
AND CN.DEL_YN = 'N'
AND CN.ID > #{filter.lastId}
ORDER BY CN.ID LIMIT #{pageRowCount} + 1;
